using namespace llvm;
using namespace PatternMatch;


/// Replace a select operand based on an equality comparison with the identity
/// constant of a binop.
static Instruction *foldSelectBinOpIdentity(SelectInst &Sel,
                                            const TargetLibraryInfo &TLI,
                                            InstCombinerImpl &IC) {
  // The select condition must be an equality compare with a constant operand.
  Value *X;
  Constant *C;
  CmpPredicate Pred;
  if (!match(Sel.getCondition(), m_Cmp(Pred, m_Value(X), m_Constant(C))))
    return nullptr;

  bool IsEq;
  if (ICmpInst::isEquality(Pred))
    IsEq = Pred == ICmpInst::ICMP_EQ;
  else if (Pred == FCmpInst::FCMP_OEQ)
    IsEq = true;
  else if (Pred == FCmpInst::FCMP_UNE)
    IsEq = false;
  else
    return nullptr;

  // A select operand must be a binop.
  BinaryOperator *BO;
  if (!match(Sel.getOperand(IsEq ? 1 : 2), m_BinOp(BO)))
    return nullptr;

  // The compare constant must be the identity constant for that binop.
  // If this a floating-point compare with 0.0, any zero constant will do.
  Type *Ty = BO->getType();
  Constant *IdC = ConstantExpr::getBinOpIdentity(BO->getOpcode(), Ty, true);
  if (IdC != C) {
    if (!IdC || !CmpInst::isFPPredicate(Pred))
      return nullptr;
    if (!match(IdC, m_AnyZeroFP()) || !match(C, m_AnyZeroFP()))
      return nullptr;
  }

  // Last, match the compare variable operand with a binop operand.
  Value *Y;
  if (!BO->isCommutative() && !match(BO, m_BinOp(m_Value(Y), m_Specific(X))))
    return nullptr;
  if (!match(BO, m_c_BinOp(m_Value(Y), m_Specific(X))))
    return nullptr;

  // +0.0 compares equal to -0.0, and so it does not behave as required for this
  // transform. Bail out if we can not exclude that possibility.
  if (isa<FPMathOperator>(BO))
    if (!BO->hasNoSignedZeros() &&
        !cannotBeNegativeZero(Y, 0,
                              IC.getSimplifyQuery().getWithInstruction(&Sel)))
      return nullptr;

  // BO = binop Y, X
  // S = { select (cmp eq X, C), BO, ? } or { select (cmp ne X, C), ?, BO }
  // =>
  // S = { select (cmp eq X, C),  Y, ? } or { select (cmp ne X, C), ?,  Y }
  return IC.replaceOperand(Sel, IsEq ? 1 : 2, Y);
}

/// This folds:
///  select (icmp eq (and X, C1)), TC, FC
///    iff C1 is a power 2 and the difference between TC and FC is a power-of-2.
/// To something like:
///  (shr (and (X, C1)), (log2(C1) - log2(TC-FC))) + FC
/// Or:
///  (shl (and (X, C1)), (log2(TC-FC) - log2(C1))) + FC
/// With some variations depending if FC is larger than TC, or the shift
/// isn't needed, or the bit widths don't match.
static Value *foldSelectICmpAnd(SelectInst &Sel, Value *CondVal, Value *TrueVal,
                                Value *FalseVal, InstCombiner::BuilderTy &Builder) {
  ICmpInst::Predicate Pred;
  Value *LHS, *RHS;
  if (!match(CondVal, m_ICmp(Pred, m_Value(LHS), m_Value(RHS))))
    return nullptr;

  if (Pred != ICmpInst::ICMP_EQ && Pred != ICmpInst::ICMP_NE)
    return nullptr;

  Value *And, *Zero;
  if (!match(LHS, m_And(m_Value(And), m_Value())) &&
      !match(RHS, m_Zero()))
    return nullptr;

  Value *X;
  ConstantInt *C1;
  if (!match(And, m_And(m_Value(X), m_ConstantInt(C1))))
    return nullptr;

  if (!C1->getValue().isPowerOf2())
    return nullptr;

  ConstantInt *TC, *FC;
  if (!match(TrueVal, m_ConstantInt(TC)) ||
      !match(FalseVal, m_ConstantInt(FC)))
    return nullptr;

  // If the predicate is NE, we have to swap the true/false constants.
  if (Pred == ICmpInst::ICMP_NE)
    std::swap(TC, FC);

  // Calculate the difference between the true and false constants.
  APInt Diff = TC->getValue() - FC->getValue();
  if (!Diff.isSignBit() && !Diff.isPowerOf2())
    return nullptr;

  // The difference must be a power-of-2.
  APInt AbsDiff = Diff.abs();
  if (!AbsDiff.isPowerOf2())
    return nullptr;

  // Check if the bitwidth of the select is at least as large as the bitwidth
  // of the condition.
  unsigned SelectWidth = Sel.getType()->getScalarSizeInBits();
  unsigned CondWidth = C1->getType()->getScalarSizeInBits();
  if (SelectWidth < CondWidth)
    return nullptr;

  // Extend the and to the width of the select.
  Value *V = Builder.CreateZExt(And, Sel.getType());

  // Calculate the shift amount.
  unsigned C1LeadingZeros = C1->getValue().log2();
  unsigned DiffLeadingZeros = AbsDiff.log2();

  if (C1LeadingZeros > DiffLeadingZeros) {
    V = Builder.CreateLShr(V, C1LeadingZeros - DiffLeadingZeros);
  } else if (C1LeadingZeros < DiffLeadingZeros) {
    V = Builder.CreateShl(V, DiffLeadingZeros - C1LeadingZeros);
  }

  if (Diff.isNegative())
    V = Builder.CreateSub(FC, V);
  else
    V = Builder.CreateAdd(V, FC);

  return V;
}

/// This folds:
///  select (icmp pred (add|sub X, C1)), TC, FC
/// To something like:
///  (add|sub (select (icmp pred X, -C1)), TC, FC)
/// This is only profitable if the select can be folded.
static Value *foldSelectICmpAdd(SelectInst &Sel, Value *CondVal,
                                Value *TrueVal, Value *FalseVal,
                                InstCombiner::BuilderTy &Builder,
                                InstCombinerImpl &IC) {
  ICmpInst::Predicate Pred;
  Value *LHS, *RHS;
  if (!match(CondVal, m_ICmp(Pred, m_Value(LHS), m_Value(RHS))))
    return nullptr;

  Value *X;
  ConstantInt *C1;
  Instruction::BinaryOps Opcode;
  if (!match(LHS, m_BinOp(Opcode, m_Value(X), m_ConstantInt(C1))) ||
      (Opcode != Instruction::Add && Opcode != Instruction::Sub))
    return nullptr;

  ConstantInt *C2;
  if (!match(RHS, m_ConstantInt(C2)))
    return nullptr;

  // We must be able to fold the new select.
  Constant *NewC = ConstantExpr::get(Opcode, C2, C1);
  Value *NewCond = Builder.CreateICmp(Pred, X, NewC);
  if (Value *V = simplifySelectInst(NewCond, TrueVal, FalseVal,
                                    IC.getSimplifyQuery().getWithInstruction(&Sel)))
    return V;

  return nullptr;
}

/// This folds:
///  select (icmp pred X, Y), (op T, F), F
/// To:
///  op (select (icmp pred X, Y), T, F), F
/// If `op` is `add` or `sub` and F is a constant.
static Value *foldSelectOpConst(SelectInst &Sel, Value *CondVal,
                                Value *TrueVal, Value *FalseVal,
                                InstCombiner::BuilderTy &Builder) {
  Value *T;
  Constant *F;
  Instruction::BinaryOps Opcode;
  if (!match(TrueVal, m_BinOp(Opcode, m_Value(T), m_Constant(F))) ||
      (Opcode != Instruction::Add && Opcode != Instruction::Sub))
    return nullptr;

  if (F != FalseVal)
    return nullptr;

  Value *NewSel = Builder.CreateSelect(CondVal, T, F);
  return Builder.CreateBinOp(Opcode, NewSel, F);
}

