  if (!CondVal->hasOneUse())
    return nullptr;

  ICmpInst::Predicate Pred;
  Value *LHS, *RHS;
  if (!match(CondVal, m_ICmp(Pred, m_Value(LHS), m_Value(RHS))))
    return nullptr;

  Value *C, *X, *Y;
  if (!match(LHS, m_Select(m_Value(C), m_Value(X), m_Value(Y))))
    return nullptr;

  ConstantInt *Z;
  if (!match(RHS, m_ConstantInt(Z)))
    return nullptr;

  // We are looking for cases where the compare is always true or always false.
  // For example:
  //   (select C, X, Y) > 10
  // If we know that X > 10 and Y > 10, then the compare is always true.
  ConstantRange RangeX = getConstantRange(X, &Sel);
  ConstantRange RangeY = getConstantRange(Y, &Sel);
  if (RangeX.isRelational(Pred, Z->getValue()) &&
      RangeY.isRelational(Pred, Z->getValue()))
    return TrueVal;
  if (RangeX.isRelational(ICmpInst::getInversePredicate(Pred), Z->getValue()) &&
      RangeY.isRelational(ICmpInst::getInversePredicate(Pred), Z->getValue()))
    return FalseVal;

  return nullptr;
}

/// This function is a generalization of foldSelectICmpAdd.
/// It folds:
///   select (icmp pred (phi ...), Z), TC, FC
/// into a single value.
static Value *foldSelectICmpPhiSingleUse(SelectInst &Sel, Value *CondVal,
                                         Value *TrueVal, Value *FalseVal,
                                         InstCombiner::BuilderTy &Builder) {
  if (!CondVal->hasOneUse())
    return nullptr;

  ICmpInst::Predicate Pred;
  Value *LHS, *RHS;
  if (!match(CondVal, m_ICmp(Pred, m_Value(LHS), m_Value(RHS))))
    return nullptr;

  PHINode *PN;
  if (!match(LHS, m_Phi(PN)))
    return nullptr;

  ConstantInt *Z;
  if (!match(RHS, m_ConstantInt(Z)))
    return nullptr;

  // We are looking for cases where the compare is always true or always false.
  // For example:
  //   (phi ...) > 10
  // If we know that all incoming values are > 10, then the compare is always
  // true.
  bool AllTrue = true;
  bool AllFalse = true;
  for (Value *V : PN->incoming_values()) {
    ConstantRange Range = getConstantRange(V, &Sel);
    if (!Range.isRelational(Pred, Z->getValue()))
      AllTrue = false;
    if (!Range.isRelational(ICmpInst::getInversePredicate(Pred), Z->getValue()))
      AllFalse = false;
  }

  if (AllTrue)
    return TrueVal;
  if (AllFalse)
    return FalseVal;

  return nullptr;
}

/// This function is a generalization of foldSelectICmpAdd.
/// It folds:
///   select (fcmp pred (add X, C1), C2), TC, FC
/// into a single value.
static Value *foldSelectFCmpAddSingleUse(SelectInst &Sel, Value *CondVal,
                                         Value *TrueVal, Value *FalseVal,
                                         InstCombiner::BuilderTy &Builder) {
  if (!CondVal->hasOneUse())
    return nullptr;

  FCmpInst::Predicate Pred;
  Value *LHS, *RHS;
  if (!match(CondVal, m_FCmp(Pred, m_Value(LHS), m_Value(RHS))))
    return nullptr;

  Value *X;
  ConstantFP *C1;
  if (!match(LHS, m_FAdd(m_Value(X), m_ConstantFP(C1))))
    return nullptr;

  ConstantFP *C2;
  if (!match(RHS, m_ConstantFP(C2)))
    return nullptr;

  // We are looking for cases where the compare is always true or always false.
  // For example:
  //   (X + 4.0) > 10.0
  // If we know that X > 6.0, then the compare is always true.
  ConstantRange Range = getConstantRange(X, &Sel);
  if (Range.isRelational(Pred, C2->getValue().subtract(C1->getValue(),
                                                       APFloat::rmNearestTiesToEven)))
    return TrueVal;
  if (Range.isRelational(FCmpInst::getInversePredicate(Pred),
                         C2->getValue().subtract(C1->getValue(),
                                                        APFloat::rmNearestTiesToEven)))
    return FalseVal;

  return nullptr;
}

